def fixture_ids() -> tuple[str, ...]:
    """Return locked fixture ids in deterministic order."""
    return tuple(sorted(LOCKED_FIXTURE_ORACLE))

def certificate_ids() -> tuple[str, ...]:
    """Return proof-carrying certificate ids in deterministic order."""
    return tuple(sorted(CERTIFICATE_ORACLE))

def expected_issues(fixture_id: str) -> tuple[str, ...]:
    """Return the static expected issue signature for a fixture."""
    return tuple(LOCKED_FIXTURE_ORACLE[fixture_id]["issues"])
